const catalogs: Record<Exclude<Language, 'es'>, Record<string, string>> = { en, fr, pt }
const STORAGE_KEY = 'rene-workspace-language'

type Parameters = Record<string, string | number>

interface LanguageContextValue {
  language: Language
  locale: string
  option: LanguageOption
  setLanguage: (language: Language) => void
  tr: (source: string, parameters?: Parameters) => string
}

const LanguageContext = createContext<LanguageContextValue | null>(null)

function interpolate(value: string, parameters?: Parameters) {
  if (!parameters) return value
  return Object.entries(parameters).reduce(
    (result, [key, replacement]) => result.replaceAll(`{${key}}`, String(replacement)),
    value,
  )
}

export function LanguageProvider({ children }: { children: ReactNode }) {
  const [language, setLanguage] = useState<Language>('es')

  useEffect(() => {
    const frame = window.requestAnimationFrame(() => {
      const saved = localStorage.getItem(STORAGE_KEY)
      if (saved === 'es' || saved === 'en' || saved === 'fr' || saved === 'pt') setLanguage(saved)
    })
    return () => window.cancelAnimationFrame(frame)
  }, [])

  const option = languageOptions.find((item) => item.code === language) ?? languageOptions[0]

  useEffect(() => {
    document.documentElement.lang = option.htmlLang
    const translate = (source: string) => language === 'es' ? source : catalogs[language][source] ?? source
    document.title = `Rene Salinas — ${translate('Full Stack Developer')}`
    document.querySelector('meta[name="description"]')?.setAttribute(
      'content',
      translate('Productos web, APIs .NET y software para operaciones construido de punta a punta.'),
    )
    localStorage.setItem(STORAGE_KEY, language)
  }, [language, option.htmlLang])

  const value = useMemo<LanguageContextValue>(() => ({
    language,
    locale: option.locale,
    option,
    setLanguage,
    tr: (source, parameters) => interpolate(language === 'es' ? source : catalogs[language][source] ?? source, parameters),
  }), [language, option])

  return <LanguageContext.Provider value={value}>{children}</LanguageContext.Provider>
}

export function useLanguage() {
  const context = useContext(LanguageContext)
  if (!context) throw new Error('useLanguage must be used inside LanguageProvider')
  return context
}
